import React,{useState,useEffect} from "react";
import {Bar} from "react-chartjs-2";
import {
Chart as ChartJS,
CategoryScale,
LinearScale,
BarElement,
Title,
Tooltip,
Legend
} from "chart.js";

ChartJS.register(
CategoryScale,
LinearScale,
BarElement,
Title,
Tooltip,
Legend
);

function App(){

const [transactions,setTransactions] = useState([]);
const [amount,setAmount] = useState("");

useEffect(()=>{
fetchTransactions();
},[]);

const fetchTransactions = async () =>{

const res = await fetch("http://localhost:5000/transactions");
const data = await res.json();

setTransactions(data);

}

const addTransaction = async () =>{

const res = await fetch("http://localhost:5000/transaction",{

method:"POST",
headers:{
"Content-Type":"application/json"
},
body:JSON.stringify({amount})

});
alert("Transaction Added Successfully!");

await res.json();

fetchTransactions();

}
const clearTransactions =async () => {
    await fetch("http://localhost:5000/clear",{
        method:"DELETE" 
    });
fetchTransactions();
}

const chartData = {
labels: transactions.map((t,i)=>"T"+(i+1)),
datasets:[
{
label:"Savings",
data: transactions.map(t=>t.saved)
}
]
};

const totalSavings =
transactions.reduce((sum,t)=>sum + t.saved,0);
const goal=100;
const progress =(totalSavings/goal)*100;


return(

<div className="container">

<h1 className="title">
Round-Up Savings Dashboard
</h1>

<div className="card">

<input
type="number"
placeholder="Enter transaction amount"
value={amount}
onChange={(e)=>setAmount(e.target.value)}
/>

<button onClick={addTransaction}>
Add Transaction
</button>

</div>

<div className="card">

<h2>Total Saved ₹{totalSavings.toFixed(2)}</h2>

</div>
<div className="card">
    <h2>Savings Goal Progress</h2>
    <div className="progress-bar">
        <div className="progress-fill"
        style={{width:progress + "%"}}>

        </div>
    </div>
    <p>₹{totalSavings.toFixed(2)} / ₹{goal}</p>
</div>

<div className="card">

<Bar data={chartData}/>

</div>
<button onClick={clearTransactions}>
    Clear History
</button>

<div className="card history">

<h2>Transaction History</h2>


<ul>

{transactions.map((t,i)=>(
<li key={i}>
Spent ₹{t.amount} → Saved ₹{t.saved}
</li>
))}

</ul>

</div>

</div>

);

}

export default App;
